using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

public class TicketClassificationResult
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidences { get; set; } = new();
}

public class ModelMetrics
{
    public double MacroAccuracy { get; set; }
    public double MicroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
    public List<CategoryMetric> PerCategoryMetrics { get; set; } = new();
}

public class CategoryMetric
{
    public string Category { get; set; } = string.Empty;
    public double Precision { get; set; }
    public double Recall { get; set; }
    public double F1Score { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly ModelMetrics _metrics;
    private readonly string[] _categoryNames;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);
        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        (_model, _metrics, _categoryNames) = TrainAndEvaluate(dataView);
        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);
    }

    private (ITransformer model, ModelMetrics metrics, string[] categoryNames) TrainAndEvaluate(
        IDataView dataView)
    {
        // With only 6 rows we train and evaluate on the full dataset
        // to produce meaningful metrics for demonstration purposes.
        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        var model = pipeline.Fit(dataView);

        var predictions = model.Transform(dataView);

        // Extract ordered label names from the key-value metadata.
        var labelColumn = predictions.Schema["Label"];
        var keyValues = new VBuffer<ReadOnlyMemory<char>>();
        labelColumn.GetKeyValues(ref keyValues);
        var categoryNames = keyValues.DenseValues()
            .Select(v => v.ToString()).ToArray();

        var rawMetrics = _mlContext.MulticlassClassification.Evaluate(predictions);

        var metrics = new ModelMetrics
        {
            MacroAccuracy = rawMetrics.MacroAccuracy,
            MicroAccuracy = rawMetrics.MicroAccuracy,
            LogLoss = rawMetrics.LogLoss,
            LogLossReduction = rawMetrics.LogLossReduction,
            PerCategoryMetrics = rawMetrics.PerClassLogLoss
                .Select((logLoss, i) => new CategoryMetric
                {
                    Category = i < categoryNames.Length ? categoryNames[i] : $"Class {i}",
                    Precision = rawMetrics.ConfusionMatrix.PerClassPrecision[i],
                    Recall = rawMetrics.ConfusionMatrix.PerClassRecall[i],
                    F1Score = 2 * rawMetrics.ConfusionMatrix.PerClassPrecision[i]
                              * rawMetrics.ConfusionMatrix.PerClassRecall[i]
                              / (rawMetrics.ConfusionMatrix.PerClassPrecision[i]
                                 + rawMetrics.ConfusionMatrix.PerClassRecall[i])
                })
                .ToList()
        };

        return (model, metrics, categoryNames);
    }

    public TicketClassificationResult Predict(TicketRequest request)
    {
        var ticketData = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(ticketData);

        var confidences = new Dictionary<string, float>();
        for (int i = 0; i < prediction.Score.Length && i < _categoryNames.Length; i++)
        {
            confidences[_categoryNames[i]] = prediction.Score[i];
        }

        return new TicketClassificationResult
        {
            PredictedCategory = prediction.Category,
            Confidences = confidences
        };
    }

    public ModelMetrics GetMetrics() => _metrics;
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly TicketClassifierService _classifier;

    public TicketsController(TicketClassifierService classifier)
    {
        _classifier = classifier;
    }

    [HttpPost("classify")]
    public ActionResult<TicketClassificationResult> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var result = _classifier.Predict(request);
        return Ok(result);
    }

    [HttpGet("metrics")]
    public ActionResult<ModelMetrics> GetMetrics()
    {
        return Ok(_classifier.GetMetrics());
    }
}

